descriptor.templateCss:
.cw{width:100%;height:100%;background:#0d1117;border-radius:12px;display:flex;flex-direction:column;gap:8px;padding:10px;box-sizing:border-box;font-family:'Segoe UI',sans-serif;overflow:hidden}
/* HEADER */
.cw-hdr{background:linear-gradient(90deg,#0f172a,#1e293b);border-radius:9px;display:flex;align-items:center;gap:12px;padding:8px 14px;border:1px solid rgba(255,255,255,.07);flex-shrink:0}
.cw-hdr-l{display:flex;align-items:center;gap:10px;flex:1;min-width:0}
.cw-pulse{width:11px;height:11px;border-radius:50%;background:#334155;flex-shrink:0;transition:all .4s}
.cw-logo{width:36px;height:36px;background:rgba(59,130,246,.15);border:1.5px solid rgba(59,130,246,.4);border-radius:7px;display:flex;align-items:center;justify-content:center;font-size:8px;font-weight:800;color:#3b82f6;letter-spacing:.05em;flex-shrink:0}
.cw-mname{font-size:13px;font-weight:800;color:#fff;white-space:nowrap}
.cw-msub{font-size:10px;color:rgba(255,255,255,.38)}
.cw-hdr-c{flex-shrink:0}
.cw-state-pill{font-size:11px;font-weight:700;padding:4px 14px;border-radius:20px;border:1.5px solid #334155;color:#94a3b8;text-transform:uppercase;letter-spacing:.07em;transition:all .4s}
.cw-hdr-r{display:flex;align-items:center;gap:14px;flex-shrink:0}
.cw-hstat{display:flex;align-items:baseline;gap:2px}
.cw-hv{font-size:17px;font-weight:800}
.cw-hu{font-size:9px;color:rgba(255,255,255,.4)}
.cw-clock{font-size:11px;color:rgba(255,255,255,.3);font-family:monospace}
/* KPI ROW */
.cw-kpi-row{display:grid;grid-template-columns:repeat(6,1fr);gap:7px;flex-shrink:0}
.cw-kpi{background:#0f172a;border-radius:8px;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:8px 4px;position:relative;overflow:hidden;border-top:2px solid #334155;transition:border-top-color .4s;min-height:70px}
.cw-ki{font-size:16px;margin-bottom:3px}
.cw-kv{font-size:clamp(14px,2.2vw,24px);font-weight:800;color:#fff;line-height:1;transition:color .4s}
.cw-ku{font-size:8px;color:rgba(255,255,255,.35);margin-top:1px}
.cw-kl{font-size:8px;color:rgba(255,255,255,.45);margin-top:4px;text-transform:uppercase;letter-spacing:.06em;text-align:center}
.cw-kbar{position:absolute;bottom:0;left:0;height:2px;background:#334155;transition:width .6s ease,background .4s;border-radius:2px}
/* GAUGES */
.cw-gauges{display:grid;grid-template-columns:repeat(4,1fr);gap:7px;flex-shrink:0}
.cw-gauge-card{background:#0f172a;border-radius:8px;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:6px}
.cw-gsvg{width:100%;max-width:140px}
.cw-gzone{font-size:9px;font-weight:700;padding:2px 10px;border-radius:20px;margin-top:2px;letter-spacing:.05em;text-transform:uppercase;background:rgba(51,65,85,.5);color:#64748b;transition:all .4s}
/* BOTTOM */
.cw-bottom{display:grid;grid-template-columns:1fr 2fr;gap:7px;flex:1;min-height:0}
.cw-status-box,.cw-prod-box{background:#0f172a;border-radius:8px;padding:10px 12px;display:flex;flex-direction:column;gap:5px;overflow:hidden}
.cw-box-title{font-size:9px;color:rgba(255,255,255,.35);text-transform:uppercase;letter-spacing:.07em;margin-bottom:3px;flex-shrink:0}
.cw-srow{display:flex;align-items:center;gap:7px}
.cw-sdot{width:7px;height:7px;border-radius:50%;background:#334155;flex-shrink:0;transition:all .3s}
.cw-sk{font-size:11px;color:rgba(255,255,255,.55);flex:1}
.cw-sv{font-size:11px;font-weight:700;color:#94a3b8;transition:color .3s}
.cw-prod-main{display:flex;align-items:baseline;gap:6px}
.cw-prod-num{font-size:36px;font-weight:800;color:#fff;transition:color .4s}
.cw-prod-sep{font-size:22px;color:rgba(255,255,255,.2)}
.cw-prod-tgt{font-size:22px;font-weight:600;color:rgba(255,255,255,.4)}
.cw-prod-sub{font-size:9px;color:rgba(255,255,255,.3);text-transform:uppercase;letter-spacing:.06em}
.cw-prog-wrap{width:100%;height:6px;background:#1e293b;border-radius:6px;overflow:hidden;margin:6px 0;flex-shrink:0}
.cw-prog-fill{height:100%;width:0%;background:#334155;border-radius:6px;transition:width .7s ease,background .4s}
.cw-attain{font-size:12px;font-weight:700;color:#64748b;transition:color .4s}
.cw-prod-row{display:flex;gap:16px;margin-top:4px}
.cw-pstat{display:flex;align-items:baseline;gap:3px}
.cw-psv{font-size:16px;font-weight:800}
.cw-psl{font-size:9px;color:rgba(255,255,255,.4)}

descriptor.controllerScript:
var ctx, timerHandle;
var STATE_COLORS = {
  'RUNNING':'#00e676','running':'#00e676','1':'#00e676',
  'STOPPED':'#ff5252','stopped':'#ff5252','0':'#ff5252',
  'IDLE':'#ffb300','idle':'#ffb300',
  'ALARM':'#ff1744','alarm':'#ff1744',
  'FAULT':'#ff1744','fault':'#ff1744'
};
var KPI_MAX = [1, 3000, 500, 900, 120, 1];

function el(id) { return ctx.$container[0].querySelector('#' + id); }
function setEl(id, txt) { var e = el(id); if (e) e.textContent = txt; }
function setStyle(id, prop, val) { var e = el(id); if (e) e.style[prop] = val; }

function pad2(n) { return String(n).padStart(2, '0'); }
function oeeColor(pct) {
  return pct >= 75 ? '#00e676' : pct >= 50 ? '#ffb300' : '#ff5252';
}
function oeeZone(pct) {
  return pct >= 75 ? 'WORLD CLASS' : pct >= 50 ? 'IMPROVING' : 'ACTION NEEDED';
}
function boolOn(v) {
  return parseFloat(v) > 0 || v === true || v === 'true' || v === '1' || v === 'RUNNING' || v === 'ON';
}

// SVG arc gauge updater
function arcPath(pct) {
  var r = 55, cx = 70, cy = 95;
  var startA = -220 * Math.PI / 180;
  var sweep = 280 * Math.PI / 180;
  var endA = startA + (Math.min(pct, 99.9) / 100) * sweep;
  var sx = (cx + r * Math.cos(startA)).toFixed(2);
  var sy = (cy + r * Math.sin(startA)).toFixed(2);
  var ex = (cx + r * Math.cos(endA)).toFixed(2);
  var ey = (cy + r * Math.sin(endA)).toFixed(2);
  var lg = pct >= 50 ? 1 : 0;
  return 'M ' + sx + ' ' + sy + ' A ' + r + ' ' + r + ' 0 ' + lg + ' 1 ' + ex + ' ' + ey;
}

function updateGauge(idx, val) {
  var arc  = el('g-arc-'  + idx);
  var pctEl= el('g-pct-'  + idx);
  var zone = el('g-zone-' + idx);
  if (!arc || !pctEl || !zone) return;
  var n = parseFloat(val);
  if (isNaN(n)) { arc.setAttribute('stroke','#334155'); pctEl.textContent = '--%'; zone.textContent = 'NO DATA'; zone.style.background='rgba(51,65,85,.4)'; zone.style.color='#64748b'; return; }
  n = Math.max(0, Math.min(100, n));
  var c = oeeColor(n);
  arc.setAttribute('d', arcPath(n));
  arc.setAttribute('stroke', c);
  pctEl.textContent = n.toFixed(1) + '%';
  pctEl.setAttribute('fill', c);
  zone.textContent = oeeZone(n);
  zone.style.background = c + '22';
  zone.style.color = c;
  zone.style.border = '1px solid ' + c + '55';
}

function updateKPI(idx, rawVal, isStr, isAlarm) {
  var kpi = el('kpi-' + idx);
  var kv  = el('kv-'  + idx);
  var kb  = el('kb-'  + idx);
  if (!kpi || !kv || !kb) return;
  var color = '#334155', pct = 0, display = '--';
  if (rawVal !== undefined && rawVal !== null) {
    if (isAlarm) {
      var on = boolOn(rawVal);
      display = on ? 'ACTIVE' : 'OK';
      color = on ? '#ff1744' : '#00e676';
      pct = on ? 100 : 5;
    } else if (isStr) {
      var s = String(rawVal).toUpperCase().slice(0, 8);
      display = s;
      color = STATE_COLORS[String(rawVal)] || STATE_COLORS[s] || '#3b82f6';
      pct = color === '#00e676' ? 100 : color === '#ffb300' ? 50 : 20;
    } else {
      var n = parseFloat(rawVal);
      if (!isNaN(n)) {
        display = n >= 100 ? Math.round(n).toString() : n >= 10 ? n.toFixed(1) : n.toFixed(2);
        pct = Math.min(100, (n / KPI_MAX[idx]) * 100);
        color = idx === 1 ? '#00e676' : idx === 2 ? '#ffb300' : idx === 3 ? '#3b82f6' : idx === 4 ? '#a78bfa' : oeeColor(pct);
      }
    }
  }
  kv.textContent = display;
  kv.style.color = color;
  kpi.style.borderTopColor = color;
  kb.style.width = pct + '%';
  kb.style.background = color;
}

function updateStatusRow(idx, rawVal, onLabel, offLabel, onColor, offColor) {
  var dot = el('sd-' + idx);
  var sv  = el('sv-' + idx);
  if (!dot || !sv) return;
  if (rawVal === undefined || rawVal === null) return;
  var on = boolOn(rawVal);
  var c = on ? onColor : offColor;
  dot.style.background = c;
  dot.style.boxShadow = '0 0 7px ' + c + '88';
  sv.textContent = on ? onLabel : offLabel;
  sv.style.color = c;
}

self.onInit = function () {
  ctx = self.ctx;
  timerHandle = setInterval(function () {
    var d = new Date();
    setEl('cw-clock', pad2(d.getHours()) + ':' + pad2(d.getMinutes()) + ':' + pad2(d.getSeconds()));
  }, 1000);
};

self.onDataUpdated = function () {
  try {
    var v = {};
    for (var i = 0; i < ctx.data.length; i++) {
      var d = ctx.data[i];
      if (d && d.dataKey && d.data && d.data.length)
        v[d.dataKey.name] = d.data[d.data.length - 1][1];
    }

    // --- HEADER ---
    var state = String(v.machine_state || 'UNKNOWN');
    var sc = STATE_COLORS[state] || STATE_COLORS[state.toUpperCase()] || '#3b82f6';
    var pulse = el('cw-pulse');
    var pill  = el('cw-state-pill');
    if (pulse) { pulse.style.background = sc; pulse.style.boxShadow = '0 0 14px ' + sc + '99'; }
    if (pill)  { pill.textContent = state.toUpperCase().slice(0, 12); pill.style.color = sc; pill.style.borderColor = sc + '66'; }
    setEl('cw-h-spindle', v.spindle_speed ? Math.round(parseFloat(v.spindle_speed)) : '--');
    setEl('cw-h-parts',   v.part_count    ? Math.round(parseFloat(v.part_count))    : '--');
    setEl('cw-h-pgm',     v.program_no    || '--');

    // --- KPI CARDS ---
    updateKPI(0, v.machine_state, true,  false);
    updateKPI(1, v.spindle_speed, false, false);
    updateKPI(2, v.feed_rate,     false, false);
    updateKPI(3, v.part_count,    false, false);
    updateKPI(4, v.last_cycle_time_sec, false, false);
    updateKPI(5, v.alarm_active,  false, true);

    // --- OEE GAUGES ---
    updateGauge(0, v.oee_today);
    updateGauge(1, v.availability_today);
    updateGauge(2, v.performance_today);
    updateGauge(3, v.quality_today);

    // --- STATUS ROWS ---
    updateStatusRow(0, v.is_running,      'RUNNING', 'STOPPED', '#00e676', '#ff5252');
    updateStatusRow(1, v.auto_mode,       'ON',      'OFF',     '#3b82f6', '#64748b');
    updateStatusRow(2, v.motion_status,   'YES',     'NO',      '#ffb300', '#64748b');
    updateStatusRow(3, v.alarm_active,    'ACTIVE',  'OK',      '#ff1744', '#00e676');
    updateStatusRow(4, v.emergency,       'ACTIVE',  'CLEAR',   '#ff1744', '#00e676');
    updateStatusRow(5, v.run_status,      'RUNNING', 'IDLE',    '#00e676', '#64748b');

    // --- PRODUCTION ---
    var parts  = parseFloat(v.parts_today  || v.part_count  || 0) || 0;
    var target = parseFloat(v.target_today || 0) || 0;
    var good   = parseFloat(v.good_parts_today  || 0) || 0;
    var rej    = parseFloat(v.rejections_today   || 0) || 0;
    var dn     = parseFloat(v.downtime_min_shift_a || 0) + parseFloat(v.downtime_min_shift_b || 0);
    var pct    = target > 0 ? Math.min(100, (parts / target) * 100) : 0;
    var pc     = oeeColor(pct);
    setEl('cw-pnum',  Math.round(parts));
    setEl('cw-ptgt',  target > 0 ? Math.round(target) : '?');
    setEl('cw-attain', pct.toFixed(1) + '% attainment');
    setEl('cw-good',  good > 0 ? Math.round(good) : '--');
    setEl('cw-rej',   rej  > 0 ? Math.round(rej)  : '--');
    setEl('cw-dn',    dn   > 0 ? Math.round(dn)   : '--');
    setStyle('cw-pnum',   'color', pc);
    setStyle('cw-attain', 'color', pc);
    var prog = el('cw-prog');
    if (prog) { prog.style.width = pct + '%'; prog.style.background = pc; }

  } catch (e) { console.error('[CNC Widget]', e); }
};

self.onDestroy = function () {
  if (timerHandle) clearInterval(timerHandle);
};
